1	import { describe, it, expect } from "vitest";
2	import { runScenario } from "./claim-office.js";
3	
4	describe("MHPCO Claim Office", () => {
5	  // ===== Premium: empty policy and base premiums =====
6	  it("empty item list → premium 5 G (only processing fee)", () => {
7	    const result = runScenario({
8	      customer: { yearsWithMHPCO: 0 },
9	      steps: [{ op: "quote", items: [] }],
10	    });
11	    expect(result).toEqual({ results: [{ premium: 5 }] });
12	  });
13	  it.todo("single sword → base 100 + fee 5 = 105 G");
14	  it.todo("single amulet → base 60 + fee 5 = 65 G");
15	  it.todo("single staff → base 80 + fee 5 = 85 G");
16	  it.todo("single potion → base 40 + fee 5 = 45 G");
17	
18	  // ===== Components and block-of-3 discount =====
19	  it.todo("single rune (component) → base 25 + fee 5 = 30 G");
20	  it.todo("2 runes → 50 G base premium (no block) + 5 G fee = 55 G");
21	  it.todo("3 runes → 60 G base premium (block) + 5 G fee = 65 G");
22	  it.todo("4 runes → 100 G base premium (no block, requires exactly 3) + 5 G fee = 105 G");
23	  it.todo("7 runes → 175 G base premium (one block of 3 + 4 single) + 5 G fee = 180 G");
24	
25	  // ===== "Alike" components — same type only =====
26	  it.todo("2 runes + 1 moonstone → 75 G base premium (no block: different types) + 5 G fee = 80 G");
27	  it.todo("3 runes + 3 moonstones → 120 G base premium (two separate blocks) + 5 G fee = 125 G");
28	
29	  // ===== Item-specific modifiers =====
30	  it.todo("cursed sword adds 50% surcharge → 100 + 50 + 5 = 155 G");
31	  it.todo("sword with enchantment exactly 5 adds 30% high-enchantment surcharge → 100 + 30 + 5 = 135 G");
32	  it.todo("sword with enchantment 4 has no high-enchantment surcharge → 100 + 5 = 105 G");
33	  it.todo("cursed sword with enchantment 5 → both surcharges (100 + 50 + 30 + 5 = 185 G)");
34	
35	  // ===== Policy-wide modifiers =====
36	  it.todo("customer with exactly 2 years gets 20% loyalty discount → sword: 100 - 20 + 5 = 85 G");
37	  it.todo("first insurance adds 10% initial assessment surcharge → sword: 100 + 10 + 5 = 115 G");
38	  it.todo("follow-up contract (second quote) gets 15% discount → sword: 100 - 15 + 5 = 90 G");
39	
40	  // ===== Modifier scope on multi-item policies =====
41	  it.todo("cursed sword + plain amulet → 160 base + 50 curse = 210 G + 5 fee = 215 G");
42	
43	  // ===== Rounding =====
44	  it.todo("premium fractions rounded up (in MHPCO's favor) — e.g., 197.5 → 198 G");
45	
46	  // ===== Integration examples =====
47	  it.todo("newcomer with cursed sword (0 yrs, first contract, ench 3) → 165 G");
48	  it.todo("long-standing customer's second contract cursed sword (3 yrs, ench 7) → 160 G");
49	
50	  // ===== Quote error handling =====
51	  it.todo("quote with unknown item type → CLI exits non-zero with stderr message");
52	
53	  // ===== Claims: standard reimbursement =====
54	  it.todo("regular sword (steel, ench 3), damage 500 G → payout 400 G (500 - 100 deductible)");
55	  it.todo("rune damage 200 G → payout 100 G (200 - 100 deductible)");
56	
57	  // ===== Claims: special clauses =====
58	  it.todo("dragon-material sword full reimbursement: ench 5, damage 800 → payout 700");
59	  it.todo("high-enchantment (≥8) sword: steel ench 9, damage 1000 → payout 400 (50% then deductible)");
60	  it.todo("both clauses apply: dragon sword ench 9, damage 1000 → payout 400 (50% wins, then deductible)");
61	  it.todo("dragon sword exactly enchantment 8, damage 1000 → payout 400 (50% clause applies, then deductible)");
62	
63	  // ===== Deductible per damage event =====
64	  it.todo("dragon attack damages sword (500) and amulet (300) → payout 600 (deductible per item)");
65	
66	  // ===== Multiple items of same type =====
67	  it.todo("two swords, each damaged 500 by dragon → payout 800 (deductible applied to each)");
68	  it.todo("two sword damages but only one sword insured → CLI exits non-zero");
69	
70	  // ===== Cap rules =====
71	  it.todo("sword + amulet insurance sum 1600, cap 3200 enforced");
72	  it.todo("cursed sword cap based on unmodified insurance value: cap 2000");
73	  it.todo("sword + 3 runes (block): insurance sum 1750 (block discount doesn't affect sum)");
74	  it.todo("two successive 1500 claims on sword (cap 2000): first payout 1400, then 600");
75	
76	  // ===== Claim error handling =====
77	  it.todo("claim references item not in policy (amulet damage with only sword insured) → CLI exits non-zero");
78	  it.todo("claim with negative damage amount → CLI exits non-zero");
79	
80	  // ===== Payout rounding =====
81	  it.todo("payout fractions rounded down (in MHPCO's favor) — e.g., 350.5 → 350 G");
82	});
